# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

local auth_token = ngx.req.get_headers().Authorization
if not auth_token then
    ngx.log(ngx.ERR, "No Authorization header")
    return ngx.exit(401)
end

local user_role
for token in auth_token:gmatch("Bearer (.+)") do
    if token == "YOUR_AUTH_TOKEN_HERE" then
        user_role = "admin"
        break
    elseif token == "OTHER_AUTH_TOKEN_HERE" then
        user_role = "user"
        break
    end
end

if not user_role then
    ngx.log(ngx.ERR, "Invalid authentication token")
    return ngx.exit(401)
end

local restricted_endpoints = {"/admin/*", "/api/*"}
for _, endpoint in ipairs(restricted_endpoints) do
    if ngx.var.uri:match(endpoint) then
        ngx.log(ngx.INFO, "Skipping permission check for "..ngx.var.uri)
        return
    end
end

-- Example role-based permission checking (replace with your logic)
if user_role == "admin" and not ngx.var.uri:match("/api/admin") then
    ngx.log(ngx.ERR, "Admins cannot access this endpoint")
    return ngx.exit(403)
end

if user_role == "user" and ngx.var.uri:match("/api/user") then
    ngx.log(ngx.ERR, "Users can only access their own data")
    return ngx.exit(403)
end